import{a as e,n as t,o as n,r}from"./index-CpAUdw8s.js";import{t as i}from"./MathBlock-Bmbir568.js";import{n as a}from"./topics-0v0u_ElX.js";var o=n(e(),1),s=[{id:`jd-01`,topic:`joint-discrete`,difficulty:`easy`,source:`Tutorial 1, Q5.2`,sourceType:`tutorial`,type:`calculation`,prompt:`Throw two fair tetrahedra (4-sided dice). Let $X$ and $Y$ be the respective outcomes, and let $U = |X - Y|$. Determine $E(X)$ and $E|X - Y|$.`,answer:`$E(X) = 5/2$, $E|X-Y| = 5/4$`,solution:[`$X$ takes values 1, 2, 3, 4 each with probability $1/4$, so $E(X) = (1+2+3+4)/4 = 5/2$.`,`$U = |X-Y|$ takes values 0, 1, 2, 3. Count outcomes out of 16: $P(U=0)=4/16$, $P(U=1)=6/16$, $P(U=2)=4/16$, $P(U=3)=2/16$.`,`$E|X-Y| = 0 \\cdot \\tfrac{4}{16} + 1 \\cdot \\tfrac{6}{16} + 2 \\cdot \\tfrac{4}{16} + 3 \\cdot \\tfrac{2}{16} = \\tfrac{20}{16} = \\tfrac{5}{4}$.`]},{id:`jd-02`,topic:`joint-discrete`,difficulty:`easy`,source:`Tutorial 1, Q5.5a`,sourceType:`tutorial`,type:`calculation`,prompt:`In a large population, 60% favour a measure, 30% disapprove, and 10% have no opinion. Ten people are randomly chosen. Find the probability that 6 are in favour, 3 disapprove, and 1 has no opinion.`,answer:`$P = 0.1058$`,solution:[`This is a multinomial distribution with $n = 10$, $p_1 = 0.6$, $p_2 = 0.3$, $p_3 = 0.1$.`,`$P = \\frac{10!}{6!\\,3!\\,1!}\\,(0.6)^6(0.3)^3(0.1)^1$.`,`Compute: $\\frac{10!}{6!\\,3!\\,1!} = 840$, and $840 \\times 0.046656 \\times 0.027 \\times 0.1 \\approx 0.1058$.`]},{id:`jd-03`,topic:`joint-discrete`,difficulty:`easy`,source:`2023 Final, Q1a`,sourceType:`final`,type:`calculation`,prompt:`The joint pmf of $(X,Y)$ is: $P(X=x,Y=y) = cy^2$ if $x$ is odd, $P(X=x,Y=y) = cx$ if $x$ is even, for $x = 1,2,3$ and $y = 1,2,3$, and $P(X=0,Y=0) = 3c$. All other probabilities are zero. Determine $c$.`,answer:`$c = 1/37$`,solution:[`Sum all probabilities and set equal to 1. For $x=0$: contributes $3c$.`,`For $x=1$ (odd): $\\sum_{y=1}^{3} cy^2 = c(1+4+9) = 14c$. Same for $x=3$: another $14c$.`,`For $x=2$ (even): $\\sum_{y=1}^{3} c \\cdot 2 = 6c$.`,`Total: $3c + 14c + 6c + 14c = 37c = 1$, so $c = 1/37$.`]},{id:`jd-04`,topic:`joint-discrete`,difficulty:`medium`,source:`2023 Final, Q1b`,sourceType:`final`,type:`calculation`,prompt:`Using $c = 1/37$ from the previous joint pmf, determine the marginal pmf of $X$ and the conditional pmf of $X$ given $Y = 3$.`,answer:`Marginal: $f_X(0)=3/37$, $f_X(1)=f_X(3)=14/37$, $f_X(2)=6/37$. Conditional: $f_{X|Y=3}(1)=f_{X|Y=3}(3)=9/20$, $f_{X|Y=3}(2)=1/10$.`,solution:[`Marginal $f_X(x) = \\sum_y f(x,y)$: $f_X(0) = 3/37$, $f_X(1) = 14c = 14/37$, $f_X(2) = 6c = 6/37$, $f_X(3) = 14/37$.`,`For the conditional, first find $f_Y(3) = f(1,3) + f(2,3) + f(3,3) = 9c + 2c + 9c = 20c = 20/37$.`,`$f_{X|Y=3}(x) = f(x,3)/f_Y(3)$: for $x=1$: $9c/20c = 9/20$, for $x=2$: $2c/20c = 1/10$, for $x=3$: $9/20$.`]},{id:`jd-05`,topic:`joint-discrete`,difficulty:`medium`,source:`2025 Final, Q1a`,sourceType:`final`,type:`calculation`,prompt:`Three products lie on a shelf numbered 1 to 3. A customer picks two successively without replacement. Let $X$ be the first product number and $Y$ the second. Find the joint pmf and calculate $\\text{Cov}(X,Y)$. You may use $E[XY] = 11/3$.`,answer:`$f_{X,Y}(x,y) = 1/6$ for $x \\neq y$; $\\text{Cov}(X,Y) = -1/3 \\approx -0.33$`,solution:[`Without replacement: 6 equally likely outcomes $(x,y)$ with $x \\neq y$, each with probability $1/6$.`,`$E(X) = E(Y) = (1+2+3)/3 = 2$ (by symmetry, each value equally likely).`,`$\\text{Cov}(X,Y) = E[XY] - E[X]E[Y] = 11/3 - 2 \\times 2 = 11/3 - 4 = -1/3 \\approx -0.33$.`]},{id:`jd-06`,topic:`joint-discrete`,difficulty:`medium`,source:`2025 Final, Q1b`,sourceType:`final`,type:`calculation`,prompt:`A customer picks two products with preferences given by the joint table: $P(1,2)=0.21$, $P(1,3)=0.30$, $P(2,1)=0.11$, $P(2,3)=0.19$, $P(3,1)=0.04$, $P(3,2)=0.15$, all diagonal entries 0. Find $P(X \\leq 2)$, $P(X+Y \\leq 3)$, and $P(X \\leq 2 \\mid X - Y \\leq 0)$.`,answer:`$P(X \\leq 2) = 0.81$, $P(X+Y \\leq 3) = 0.32$, $P(X \\leq 2 \\mid X-Y \\leq 0) = 1.00$`,solution:[`$P(X \\leq 2) = P(X=1) + P(X=2) = (0+0.21+0.30) + (0.11+0+0.19) = 0.51 + 0.30 = 0.81$.`,`$P(X+Y \\leq 3)$: pairs with sum $\\leq 3$ are $(1,1), (1,2), (2,1)$, giving $0 + 0.21 + 0.11 = 0.32$.`,`$P(X-Y \\leq 0)$: cells where $X \\leq Y$: $(1,2)=0.21$, $(1,3)=0.30$, $(2,3)=0.19$, plus diagonal zeros $= 0.70$.`,`All those cells also have $X \\leq 2$, so $P(X \\leq 2 \\text{ and } X-Y \\leq 0) = 0.70$, giving $0.70/0.70 = 1.00$.`]},{id:`jd-07`,topic:`joint-discrete`,difficulty:`medium`,source:`Tutorial 2, Q5.34a`,sourceType:`tutorial`,type:`calculation`,prompt:`From the population $\\{1,2,3,4,5\\}$, two numbers $X$ and $Y$ are drawn successively without replacement. Calculate $\\text{Cov}(X,Y)$.`,answer:`$\\text{Cov}(X,Y) = -0.5$`,solution:[`There are $5 \\times 4 = 20$ equally likely outcomes, each with probability $1/20$.`,`$E(X) = E(Y) = 3$ by symmetry. Compute $E(XY) = \\frac{1}{20}\\sum_{x \\neq y} xy = 8.5$.`,`$\\text{Cov}(X,Y) = E(XY) - E(X)E(Y) = 8.5 - 9 = -0.5$. The negative covariance reflects that without replacement, a large first draw makes the second smaller on average.`]},{id:`jd-08`,topic:`joint-discrete`,difficulty:`easy`,source:`Tutorial 3, Q5.60d`,sourceType:`tutorial`,type:`calculation`,prompt:`The joint pmf of $(X,Y)$ is $f(x,y) = (x+y)/21$ for $x = 1,2,3$ and $y = 1,2$. Find $P(Y - X \\leq 0)$.`,answer:`$P(Y-X \\leq 0) = 6/7$`,solution:[`$Y - X \\leq 0$ means $Y \\leq X$. The only cell where $Y > X$ is $(x,y) = (1,2)$.`,`$P(X=1, Y=2) = (1+2)/21 = 3/21 = 1/7$.`,`$P(Y - X \\leq 0) = 1 - 1/7 = 6/7$.`]},{id:`jc-01`,topic:`joint-continuous`,difficulty:`easy`,source:`Tutorial 1, Q5.17a`,sourceType:`tutorial`,type:`calculation`,prompt:`The random variables $X$ and $Y$ have joint pdf $f(x,y) = cy$ on the region $0 < x < 4$ and $0 < y < 1 - x/4$. Determine $c$.`,answer:`$c = 3/2$`,solution:[`Integrate over the support and set equal to 1. Integrate $y$ first: $\\int_0^1 \\int_0^{4-4y} cy\\,dx\\,dy$.`,`Inner integral: $cy(4-4y)$. Outer: $\\int_0^1 c(4y - 4y^2)\\,dy = c[2y^2 - \\tfrac{4}{3}y^3]_0^1 = 2c/3$.`,`Set $2c/3 = 1$, so $c = 3/2$.`]},{id:`jc-02`,topic:`joint-continuous`,difficulty:`medium`,source:`Tutorial 1, Q5.17b`,sourceType:`tutorial`,type:`calculation`,prompt:`Given $f(x,y) = \\frac{3}{2}y$ on $0 < x < 4$, $0 < y < 1 - x/4$, find the marginal pdf of $X$ and compute $E(X)$.`,answer:`$f_X(x) = \\tfrac{3}{4}(1-x/4)^2$ for $0 < x < 4$; $E(X) = 1$`,solution:[`$f_X(x) = \\int_0^{1-x/4} \\frac{3}{2}y\\,dy = \\frac{3}{2} \\cdot \\frac{(1-x/4)^2}{2} = \\frac{3}{4}(1-x/4)^2$ for $0 < x < 4$.`,`$E(X) = \\int_0^4 x \\cdot \\frac{3}{4}(1-x/4)^2\\,dx$. Expanding and integrating gives $E(X) = 1$.`]},{id:`jc-03`,topic:`joint-continuous`,difficulty:`medium`,source:`Tutorial 1, Q5.17c`,sourceType:`tutorial`,type:`calculation`,prompt:`Given $f(x,y) = \\frac{3}{2}y$ on $0 < x < 4$, $0 < y < 1 - x/4$, find the marginal pdf of $Y$ and compute $E(Y)$.`,answer:`$f_Y(y) = 6y - 6y^2$ for $0 < y < 1$; $E(Y) = 1/2$`,solution:[`$f_Y(y) = \\int_0^{4-4y} \\frac{3}{2}y\\,dx = \\frac{3}{2}y(4-4y) = 6y - 6y^2$ for $0 < y < 1$.`,`$E(Y) = \\int_0^1 y(6y - 6y^2)\\,dy = \\int_0^1 (6y^2 - 6y^3)\\,dy = [2y^3 - \\tfrac{3}{2}y^4]_0^1 = 2 - 3/2 = 1/2$.`]},{id:`jc-04`,topic:`joint-continuous`,difficulty:`medium`,source:`2024 Final, Q1c`,sourceType:`final`,type:`calculation`,prompt:`Let $X$ and $Y$ have joint pdf $f(x,y) = cxy$ for $0 < x < 1$, $ax < y < bx$, where $c > 0$ and $0 < a < b$. Compute $c$ as a function of $a$ and $b$.`,answer:`$c = 8/(b^2 - a^2)$`,solution:[`Set $\\int_0^1 \\int_{ax}^{bx} cxy\\,dy\\,dx = 1$.`,`Inner integral: $\\int_{ax}^{bx} cxy\\,dy = cx \\cdot \\frac{b^2x^2 - a^2x^2}{2} = \\frac{c}{2}(b^2-a^2)x^3$.`,`Outer integral: $\\frac{c}{2}(b^2-a^2)\\int_0^1 x^3\\,dx = \\frac{c}{2}(b^2-a^2) \\cdot \\frac{1}{4} = \\frac{c(b^2-a^2)}{8}$.`,`Set equal to 1: $c = 8/(b^2 - a^2)$.`]},{id:`jc-05`,topic:`joint-continuous`,difficulty:`hard`,source:`2024 Final, Q1d`,sourceType:`final`,type:`calculation`,prompt:`With joint pdf $f(x,y) = cxy$ on $0 < x < 1$, $ax < y < bx$ (where $0 < a < b$), determine the marginal pdf of $Y$ and its support.`,answer:`$f_Y(y)$ is piecewise: one form for $0 < y \\leq a$ and another for $a < y < b$.`,solution:[`For fixed $y$, integrate over valid $x$. From $ax < y < bx$: $y/b < x < y/a$, but also $0 < x < 1$.`,`Case 1: $0 < y \\leq a$ — then $y/a \\leq 1$, so $x \\in (y/b, y/a)$. $f_Y(y) = \\int_{y/b}^{y/a} cxy\\,dx = \\frac{cy}{2}(y^2/a^2 - y^2/b^2) = \\frac{c}{2}(1/a^2 - 1/b^2)y^3$.`,`Case 2: $a < y < b$ — then $y/a > 1$, so $x \\in (y/b, 1)$. $f_Y(y) = \\int_{y/b}^1 cxy\\,dx = \\frac{cy}{2}(1 - y^2/b^2)$.`,`Substituting $c = 8/(b^2-a^2)$ gives the explicit formulas.`]},{id:`jc-06`,topic:`joint-continuous`,difficulty:`medium`,source:`2025 Final, Q1d`,sourceType:`final`,type:`calculation`,prompt:`The joint pdf of $(S,T)$ is $f(s,t) = c\\lambda e^{-\\lambda(s+t)}$ for $0 < s < t$ and $\\lambda > 0$. Determine $c$ such that this is a proper pdf.`,answer:`$c = 2\\lambda$`,solution:[`Require $\\int_0^\\infty \\int_0^t c\\lambda e^{-\\lambda(s+t)}\\,ds\\,dt = 1$.`,`Inner integral: $c\\lambda e^{-\\lambda t} \\cdot \\frac{1}{\\lambda}(1 - e^{-\\lambda t}) = c(e^{-\\lambda t} - e^{-2\\lambda t})$.`,`Outer integral: $c\\left[\\frac{1}{\\lambda} - \\frac{1}{2\\lambda}\\right] = \\frac{c}{2\\lambda}$.`,`Set $c/(2\\lambda) = 1$, so $c = 2\\lambda$.`]},{id:`jc-07`,topic:`joint-continuous`,difficulty:`medium`,source:`2025 Final, Q1e`,sourceType:`final`,type:`calculation`,prompt:`Given $f_{S,T}(s,t) = 2\\lambda^2 e^{-\\lambda(s+t)}$ for $0 < s < t$ and 0 otherwise, determine the marginal pdf of $S$.`,answer:`$f_S(s) = 2\\lambda e^{-2\\lambda s}$ for $s > 0$, i.e. $S \\sim \\text{Exp}(2\\lambda)$`,solution:[`$f_S(s) = \\int_s^\\infty 2\\lambda^2 e^{-\\lambda(s+t)}\\,dt = 2\\lambda^2 e^{-\\lambda s} \\cdot \\frac{1}{\\lambda} e^{-\\lambda s} = 2\\lambda e^{-2\\lambda s}$.`,`This is the pdf of an $\\text{Exp}(2\\lambda)$ distribution, valid for $s > 0$.`]},{id:`jc-08`,topic:`joint-continuous`,difficulty:`medium`,source:`2023 Final, Q1c`,sourceType:`final`,type:`calculation`,prompt:`The joint pdf of $(U,V)$ is $f(u,v) = \\frac{6}{7}u$ for $0 < u < 1$ and $u < v < 2u^2 + 2$. Determine the marginal pdf of $U$.`,answer:`$f_U(u) = \\frac{6}{7}u(2u^2 + 2 - u)$ for $u \\in (0,1)$`,solution:[`$f_U(u) = \\int_u^{2u^2+2} \\frac{6}{7}u\\,dv = \\frac{6}{7}u(2u^2 + 2 - u)$.`,`This is valid for $u \\in (0,1)$, and zero otherwise.`]},{id:`jc-09`,topic:`joint-continuous`,difficulty:`easy`,source:`Resit 2024, Q1a`,sourceType:`resit`,type:`calculation`,prompt:`The joint pdf of $(X,Y)$ is $f(x,y) = \\frac{1}{2\\pi}e^{-\\frac{1}{2}(x^2+y^2)}$ for $x,y \\in \\mathbb{R}$. What is the marginal distribution of $X$?`,answer:`$X \\sim N(0,1)$`,solution:[`The joint pdf factors: $f(x,y) = \\frac{1}{\\sqrt{2\\pi}}e^{-x^2/2} \\cdot \\frac{1}{\\sqrt{2\\pi}}e^{-y^2/2}$.`,`The first factor is the pdf of $N(0,1)$. Since $f(x,y) = f_X(x) \\cdot f_Y(y)$, we identify $X \\sim N(0,1)$.`]},{id:`ev-01`,topic:`expected-values`,difficulty:`easy`,source:`Tutorial 2, Q5.32a`,sourceType:`tutorial`,type:`calculation`,prompt:`An unbiased die is thrown twice, giving counts $X$ and $Y$. Calculate $\\text{Cov}(X, X+Y)$.`,answer:`$\\text{Cov}(X, X+Y) = 35/12$`,solution:[`$\\text{Cov}(X, X+Y) = \\text{Cov}(X,X) + \\text{Cov}(X,Y) = \\text{Var}(X) + 0$.`,`The throws are independent, so $\\text{Cov}(X,Y) = 0$. For a fair die, $\\text{Var}(X) = 35/12$.`,`Therefore $\\text{Cov}(X, X+Y) = 35/12$.`]},{id:`ev-02`,topic:`expected-values`,difficulty:`easy`,source:`Tutorial 2, Q5.32d`,sourceType:`tutorial`,type:`conceptual`,prompt:`Two independent fair dice $X, Y$ are thrown. Is $\\text{Var}(X+Y)$ equal to $\\text{Var}(2X)$? Explain.`,answer:`No. $\\text{Var}(X+Y) = 2\\,\\text{Var}(X)$ but $\\text{Var}(2X) = 4\\,\\text{Var}(X)$.`,solution:[`By independence: $\\text{Var}(X+Y) = \\text{Var}(X) + \\text{Var}(Y) = 2\\,\\text{Var}(X)$.`,`By the scaling property: $\\text{Var}(2X) = 4\\,\\text{Var}(X)$.`,`Since $2\\,\\text{Var}(X) \\neq 4\\,\\text{Var}(X)$, they are not equal. Adding an independent copy is not the same as doubling.`]},{id:`ev-03`,topic:`expected-values`,difficulty:`medium`,source:`Tutorial 2, Q5.41`,sourceType:`tutorial`,type:`calculation`,prompt:`Given $\\text{Var}(X) = 10$, $\\text{Var}(Y) = 20$, and $\\rho(X,Y) = 1/2$. Determine $\\text{Var}(2X - 3Y)$.`,answer:`$\\text{Var}(2X-3Y) = 220 - 60\\sqrt{2} \\approx 135.1$`,solution:[`$\\text{Cov}(X,Y) = \\rho \\cdot \\sigma_X \\cdot \\sigma_Y = \\frac{1}{2}\\sqrt{10}\\sqrt{20} = \\frac{1}{2}\\sqrt{200} = 5\\sqrt{2}$.`,`$\\text{Var}(2X - 3Y) = 4\\,\\text{Var}(X) + 9\\,\\text{Var}(Y) - 12\\,\\text{Cov}(X,Y)$.`,`$= 40 + 180 - 60\\sqrt{2} = 220 - 60\\sqrt{2} \\approx 135.1$.`]},{id:`ev-04`,topic:`expected-values`,difficulty:`medium`,source:`Tutorial 2, Q5.34b`,sourceType:`tutorial`,type:`calculation`,prompt:`From $\\{1,2,3,4,5\\}$, two numbers are drawn without replacement. Given $\\text{Cov}(X,Y) = -0.5$ and $\\text{Var}(X) = 2$, find $E(X+Y)$ and $\\text{Var}(X+Y)$.`,answer:`$E(X+Y) = 6$, $\\text{Var}(X+Y) = 3$`,solution:[`$E(X+Y) = E(X) + E(Y) = 3 + 3 = 6$.`,`$\\text{Var}(X+Y) = \\text{Var}(X) + \\text{Var}(Y) + 2\\,\\text{Cov}(X,Y) = 2 + 2 + 2(-0.5) = 3$.`,`Note: $\\text{Var}(X) = \\text{Var}(Y) = 2$ since both draws have the same marginal distribution.`]},{id:`ev-05`,topic:`expected-values`,difficulty:`medium`,source:`2025 Final, Q1c`,sourceType:`final`,type:`calculation`,prompt:`From the joint table in Q1b (product selection with preferences), find $E[X-Y]$ and $\\text{Var}(X-Y)$. The distribution of $X-Y$ is: $P(-2)=0.30$, $P(-1)=0.40$, $P(0)=0$, $P(1)=0.26$, $P(2)=0.04$.`,answer:`$E[X-Y] = -0.66$, $\\text{Var}(X-Y) \\approx 1.58$`,solution:[`$E[X-Y] = (-2)(0.30) + (-1)(0.40) + 0 + (1)(0.26) + (2)(0.04) = -0.66$.`,`$E[(X-Y)^2] = 4(0.30) + 1(0.40) + 0 + 1(0.26) + 4(0.04) = 2.02$.`,`$\\text{Var}(X-Y) = 2.02 - (-0.66)^2 = 2.02 - 0.4356 \\approx 1.58$.`]},{id:`ev-06`,topic:`expected-values`,difficulty:`hard`,source:`2023 Final, Q1d`,sourceType:`final`,type:`calculation`,prompt:`Let $G|H=h \\sim \\text{Unif}(h, 2h^2+2)$ and $H \\sim \\text{Poi}(8)$. Compute $E[G]$.`,answer:`$E[G] = 77$`,solution:[`Use iterated expectation: $E[G] = E[E[G|H]]$.`,`$E[G|H=h] = (h + 2h^2 + 2)/2$, so $E[G|H] = (H + 2H^2 + 2)/2$.`,`$E[G] = \\frac{1}{2}E[H] + E[H^2] + 1$. Since $H \\sim \\text{Poi}(8)$: $E[H] = 8$, $E[H^2] = \\text{Var}(H) + (E[H])^2 = 8 + 64 = 72$.`,`$E[G] = 4 + 72 + 1 = 77$.`]},{id:`ev-07`,topic:`expected-values`,difficulty:`medium`,source:`Tutorial 4, Q5.68a`,sourceType:`tutorial`,type:`calculation`,prompt:`Let $X \\sim \\text{Poi}(3)$ be the number of ATM customers per minute, and $Y$ the number who withdraw. Given $E(Y|X) = X/2$, find $E(Y)$.`,answer:`$E(Y) = 3/2$`,solution:[`By the law of iterated expectation: $E(Y) = E[E(Y|X)] = E[X/2] = E(X)/2$.`,`Since $X \\sim \\text{Poi}(3)$: $E(X) = 3$, so $E(Y) = 3/2$.`]},{id:`ev-08`,topic:`expected-values`,difficulty:`medium`,source:`Tutorial 4, Q5.68b`,sourceType:`tutorial`,type:`calculation`,prompt:`With $X \\sim \\text{Poi}(3)$, $E(Y|X) = X/2$, and $\\text{Var}(Y|X) = (X+1)/3$, find $\\text{Var}(Y)$.`,answer:`$\\text{Var}(Y) = 25/12$`,solution:[`Law of total variance: $\\text{Var}(Y) = E[\\text{Var}(Y|X)] + \\text{Var}(E[Y|X])$.`,`$E[\\text{Var}(Y|X)] = E[(X+1)/3] = (E(X)+1)/3 = 4/3$.`,`$\\text{Var}(E[Y|X]) = \\text{Var}(X/2) = \\text{Var}(X)/4 = 3/4$.`,`$\\text{Var}(Y) = 4/3 + 3/4 = 25/12$.`]},{id:`ev-09`,topic:`expected-values`,difficulty:`hard`,source:`Tutorial 4, Q5.68c`,sourceType:`tutorial`,type:`calculation`,prompt:`With $X \\sim \\text{Poi}(3)$ and $E(Y|X) = X/2$, find $E(XY)$.`,answer:`$E(XY) = 6$`,solution:[`$E(XY) = E[E(XY|X)]$. Given $X$: $E(XY|X) = X \\cdot E(Y|X) = X \\cdot X/2 = X^2/2$.`,`$E(XY) = E[X^2/2] = E(X^2)/2$. For $\\text{Poi}(3)$: $E(X^2) = \\text{Var}(X) + (E(X))^2 = 3 + 9 = 12$.`,`$E(XY) = 12/2 = 6$.`]},{id:`in-01`,topic:`independence`,difficulty:`easy`,source:`2024 Final, Q1b`,sourceType:`final`,type:`conceptual`,prompt:`The joint pdf is $f(x,y) = cxy$ on the region $0 < x < 1$, $ax < y < bx$. Are $X$ and $Y$ independent? Justify.`,answer:`No, $X$ and $Y$ are not independent.`,solution:[`The support is the region between lines $y = ax$ and $y = bx$ for $0 < x < 1$ — a wedge shape.`,`This is NOT a Cartesian product of the marginal supports.`,`Since the support is not rectangular, $f(x,y)$ cannot factor as $f_X(x) \\cdot f_Y(y)$, so $X$ and $Y$ are dependent.`]},{id:`in-02`,topic:`independence`,difficulty:`easy`,source:`2025 Final, Q2b`,sourceType:`final`,type:`conceptual`,prompt:`The joint pdf is $f(x,y) = 6xy$ for $0 < x < 1$ and $0 < y < \\sqrt{x}$. Are $X$ and $Y$ independent?`,answer:`No, $X$ and $Y$ are not independent.`,solution:[`The support is $\\{(x,y): 0 < x < 1, 0 < y < \\sqrt{x}\\}$ — the region below $y = \\sqrt{x}$.`,`The marginal support of $X$ is $(0,1)$ and of $Y$ is $(0,1)$, but the joint support is not $(0,1) \\times (0,1)$.`,`Since the support is not a rectangle (Cartesian product), $X$ and $Y$ cannot be independent.`]},{id:`in-03`,topic:`independence`,difficulty:`medium`,source:`Tutorial 2, Q5.32c`,sourceType:`tutorial`,type:`conceptual`,prompt:`Two fair dice $X, Y$ are thrown independently. Are $X-Y$ and $X+Y$ independent? (Note: they are uncorrelated.)`,answer:`No, $X-Y$ and $X+Y$ are NOT independent despite being uncorrelated.`,solution:[`$\\text{Cov}(X-Y, X+Y) = \\text{Var}(X) - \\text{Var}(Y) = 0$ since $X$ and $Y$ have the same distribution, so they are uncorrelated.`,`But consider: if $X-Y = 5$, then $X=6, Y=1$ (forced), so $X+Y = 7$. The value of $X-Y$ constrains $X+Y$.`,`More formally: $P(X-Y=5) = 1/36$, $P(X+Y=12) = 1/36$, but $P(X-Y=5 \\text{ and } X+Y=12) = P(X=8.5) = 0 \\neq \\frac{1}{36} \\cdot \\frac{1}{36}$.`]},{id:`in-04`,topic:`independence`,difficulty:`easy`,source:`Tutorial 3, Q5.46a`,sourceType:`tutorial`,type:`proof`,prompt:`Prove that if $X$ and $Y$ are independent, then $\\text{Cov}(X,Y) = 0$.`,answer:`Use $E(XY) = E(X)E(Y)$ for independent variables.`,solution:[`If $X$ and $Y$ are independent, then $E(XY) = E(X) \\cdot E(Y)$.`,`$\\text{Cov}(X,Y) = E(XY) - E(X)E(Y) = E(X)E(Y) - E(X)E(Y) = 0$.`,`And $\\rho(X,Y) = \\text{Cov}(X,Y)/(\\sigma_X \\sigma_Y) = 0$.`]},{id:`in-05`,topic:`independence`,difficulty:`medium`,source:`Tutorial 3, Q5.46b`,sourceType:`tutorial`,type:`conceptual`,prompt:`$(X,Y)$ is uniformly distributed on the diamond $|x|+|y| \\leq 1$. Show that $\\text{Cov}(X,Y) = 0$ but $X$ and $Y$ are dependent.`,answer:`Uncorrelated but dependent: $\\text{Cov} = 0$ but the support is not rectangular.`,solution:[`By symmetry of the diamond around both axes: $E(X) = 0$, $E(Y) = 0$.`,`By symmetry, $E(XY) = 0$ as well (the integrand $xy$ is odd in both $x$ and $y$). So $\\text{Cov}(X,Y) = 0$.`,`However, $X$ and $Y$ are dependent: the support $|x|+|y| \\leq 1$ is a diamond, not a rectangle. For example, if $X = 0.9$, then $|Y| \\leq 0.1$.`]},{id:`in-06`,topic:`independence`,difficulty:`easy`,source:`Tutorial 5, Q6.5a`,sourceType:`tutorial`,type:`conceptual`,prompt:`The joint pdf is $f(x,y) = 2x/25$ on $0 < x < 5$ and $0 < y < 3 - 0.6x$. Are $X$ and $Y$ independent?`,answer:`No.`,solution:[`The support is a triangle with vertices at $(0,0)$, $(5,0)$, and $(0,3)$.`,`This is not a Cartesian product of intervals — it is not rectangular.`,`Therefore $X$ and $Y$ are not independent.`]},{id:`in-07`,topic:`independence`,difficulty:`medium`,source:`Resit 2024, Q1d`,sourceType:`resit`,type:`calculation`,prompt:`Given the standard bivariate normal $f(x,y) = \\frac{1}{2\\pi}e^{-\\frac{1}{2}(x^2+y^2)}$, determine $\\text{Var}[X+Y]$.`,answer:`$\\text{Var}[X+Y] = 2$`,solution:[`From the factorized joint pdf, $X$ and $Y$ are independent with $X \\sim N(0,1)$ and $Y \\sim N(0,1)$.`,`By independence: $\\text{Var}(X+Y) = \\text{Var}(X) + \\text{Var}(Y) = 1 + 1 = 2$.`]},{id:`cd-01`,topic:`conditional`,difficulty:`medium`,source:`Tutorial 3, Q5.53a`,sourceType:`tutorial`,type:`calculation`,prompt:`The joint pdf is $f(x,y) = 60x^2y$ for $x > 0$, $y > 0$, $x + y < 1$. Find the conditional pdf of $Y$ given $X = x$.`,answer:`$f_{Y|X}(y|x) = \\frac{2y}{(1-x)^2}$ for $0 < y < 1-x$`,solution:[`Find marginal: $f_X(x) = \\int_0^{1-x} 60x^2 y\\,dy = 60x^2 \\cdot \\frac{(1-x)^2}{2} = 30x^2(1-x)^2$.`,`$f_{Y|X}(y|x) = \\frac{f(x,y)}{f_X(x)} = \\frac{60x^2 y}{30x^2(1-x)^2} = \\frac{2y}{(1-x)^2}$ for $0 < y < 1-x$.`]},{id:`cd-02`,topic:`conditional`,difficulty:`medium`,source:`Tutorial 3, Q5.53b`,sourceType:`tutorial`,type:`calculation`,prompt:`With $f_{Y|X}(y|x) = 2y/(1-x)^2$ for $0 < y < 1-x$, find $P(Y > 0.1 \\mid X = 0.5)$.`,answer:`$P(Y > 0.1 \\mid X = 0.5) = 0.96$`,solution:[`At $x = 0.5$: $f_{Y|X=0.5}(y) = 2y/(0.5)^2 = 8y$ for $0 < y < 0.5$.`,`$P(Y > 0.1 | X = 0.5) = \\int_{0.1}^{0.5} 8y\\,dy = [4y^2]_{0.1}^{0.5} = 4(0.25) - 4(0.01) = 0.96$.`]},{id:`cd-03`,topic:`conditional`,difficulty:`medium`,source:`Tutorial 3, Q5.60b`,sourceType:`tutorial`,type:`calculation`,prompt:`The joint pmf is $f(x,y) = (x+y)/21$ for $x=1,2,3$ and $y=1,2$. Find the conditional pmf $f_{Y|X}(y|x)$.`,answer:`$f_{Y|X}(y|x) = (x+y)/(2x+3)$`,solution:[`First find $f_X(x) = \\sum_y f(x,y) = \\frac{(x+1) + (x+2)}{21} = \\frac{2x+3}{21}$.`,`$f_{Y|X}(y|x) = \\frac{f(x,y)}{f_X(x)} = \\frac{(x+y)/21}{(2x+3)/21} = \\frac{x+y}{2x+3}$ for $y = 1, 2$.`]},{id:`cd-04`,topic:`conditional`,difficulty:`medium`,source:`Tutorial 3, Q5.60c`,sourceType:`tutorial`,type:`calculation`,prompt:`With $f_{Y|X}(y|x) = (x+y)/(2x+3)$ for $y = 1,2$, find $E(Y|X=x)$.`,answer:`$E(Y|X=x) = (3x+5)/(2x+3)$`,solution:[`$E(Y|X=x) = 1 \\cdot \\frac{x+1}{2x+3} + 2 \\cdot \\frac{x+2}{2x+3} = \\frac{x+1+2x+4}{2x+3} = \\frac{3x+5}{2x+3}$.`]},{id:`cd-05`,topic:`conditional`,difficulty:`hard`,source:`2024 Final, Q1e`,sourceType:`final`,type:`calculation`,prompt:`With joint pdf $f(x,y) = cxy$ on $0 < x < 1$, $ax < y < bx$ and $c = 8/(b^2-a^2)$, determine $E[Y|X=x]$.`,answer:`$E[Y|X=x] = \\frac{2(b^3-a^3)}{3(b^2-a^2)} \\cdot x$`,solution:[`Marginal: $f_X(x) = \\frac{c}{2}(b^2-a^2)x^3 = 4x^3$.`,`Conditional: $f_{Y|X=x}(y) = \\frac{cxy}{4x^3} = \\frac{2y}{(b^2-a^2)x^2}$ for $ax < y < bx$.`,`$E[Y|X=x] = \\int_{ax}^{bx} y \\cdot \\frac{2y}{(b^2-a^2)x^2}\\,dy = \\frac{2}{(b^2-a^2)x^2} \\cdot \\frac{b^3x^3 - a^3x^3}{3}$.`,`$= \\frac{2(b^3-a^3)}{3(b^2-a^2)} \\cdot x$.`]},{id:`cd-06`,topic:`conditional`,difficulty:`medium`,source:`Resit 2024, Q1b`,sourceType:`resit`,type:`calculation`,prompt:`With joint pdf $f(x,y) = \\frac{1}{2\\pi}e^{-\\frac{1}{2}(x^2+y^2)}$, derive the conditional pdf $f_{Y|X=x}(y)$.`,answer:`$f_{Y|X=x}(y) = \\frac{1}{\\sqrt{2\\pi}}e^{-y^2/2}$, i.e. $Y|X=x \\sim N(0,1)$`,solution:[`$f_{Y|X=x}(y) = f(x,y)/f_X(x)$.`,`$= \\frac{\\frac{1}{2\\pi}e^{-(x^2+y^2)/2}}{\\frac{1}{\\sqrt{2\\pi}}e^{-x^2/2}} = \\frac{1}{\\sqrt{2\\pi}}e^{-y^2/2}$.`,`Since the joint pdf factors and the support is rectangular, $X$ and $Y$ are independent, so the conditional equals the marginal: $Y|X=x \\sim N(0,1)$.`]},{id:`cd-07`,topic:`conditional`,difficulty:`easy`,source:`Resit 2024, Q1c`,sourceType:`resit`,type:`calculation`,prompt:`Given $X \\sim N(0,1)$ and $Y \\sim N(0,1)$ independently, determine $E[X+Y]$.`,answer:`$E[X+Y] = 0$`,solution:[`$E[X+Y] = E[X] + E[Y] = 0 + 0 = 0$.`]},{id:`cd-08`,topic:`conditional`,difficulty:`medium`,source:`Tutorial 5, Q6.20c`,sourceType:`tutorial`,type:`calculation`,prompt:`Let $X_1 \\sim N(\\mu_1, \\sigma_1^2)$ and $X_2 \\sim N(\\mu_2, \\sigma_2^2)$ be independent. Define $Y_1 = X_1$ and $Y_2 = X_1 + X_2$. Find the conditional distribution of $Y_2$ given $Y_1 = y_1$.`,answer:`$Y_2 | Y_1 = y_1 \\sim N(\\mu_2 + y_1,\\, \\sigma_2^2)$`,solution:[`$(Y_1, Y_2)$ is bivariate normal with $\\rho = \\sigma_1/\\sqrt{\\sigma_1^2 + \\sigma_2^2}$.`,`Using the BVN conditional formula and simplifying: mean $= \\mu_2 + y_1$, variance $= \\sigma_2^2$.`,`Intuitively: given $Y_1 = X_1 = y_1$, we have $Y_2 = y_1 + X_2$ where $X_2 \\sim N(\\mu_2, \\sigma_2^2)$.`]},{id:`mg-01`,topic:`mgf-bivariate`,difficulty:`medium`,source:`2024 Final, Q4`,sourceType:`final`,type:`calculation`,prompt:`Let $X \\sim \\chi^2(n)$ and $Y \\sim \\chi^2(n)$ be independent, with $n > 0$. Define $U = (X+Y)/2$. Use the MGF method to identify the distribution of $U$.`,answer:`$U \\sim \\text{Gamma}(\\theta = 1, r = n)$`,solution:[`$M_U(t) = E[e^{t(X+Y)/2}] = E[e^{(t/2)X}] \\cdot E[e^{(t/2)Y}]$ by independence.`,`MGF of $\\chi^2(n)$: $(1-2t)^{-n/2}$. So $M_X(t/2) = (1-t)^{-n/2}$, same for $Y$.`,`$M_U(t) = (1-t)^{-n/2} \\cdot (1-t)^{-n/2} = (1-t)^{-n}$.`,`Comparing with $\\text{Gamma}(\\theta, r)$ MGF $(1-\\theta t)^{-r}$: $\\theta = 1$, $r = n$.`]},{id:`mg-02`,topic:`mgf-bivariate`,difficulty:`medium`,source:`Resit 2024, Q1e`,sourceType:`resit`,type:`calculation`,prompt:`Given independent $X \\sim N(0,1)$ and $Y \\sim N(0,1)$, use the MGF method to find the distribution of $W = X + Y$.`,answer:`$W \\sim N(0, 2)$`,solution:[`$M_W(t) = E[e^{t(X+Y)}] = M_X(t) \\cdot M_Y(t)$ by independence.`,`For $N(0,1)$: $M_X(t) = e^{t^2/2}$. So $M_W(t) = e^{t^2/2} \\cdot e^{t^2/2} = e^{t^2}$.`,`This is $\\exp(\\mu t + \\sigma^2 t^2/2)$ with $\\mu = 0$ and $\\sigma^2 = 2$, so $W \\sim N(0, 2)$.`]},{id:`mg-03`,topic:`mgf-bivariate`,difficulty:`medium`,source:`2023 Final, Q3a`,sourceType:`final`,type:`calculation`,prompt:`Let $X_1, \\ldots, X_n$ be a random sample from $\\text{Exp}(\\lambda)$. Use the MGF method to determine the distribution of $Y = \\sum_{i=1}^n X_i$.`,answer:`$Y \\sim \\text{Gamma}(1/\\lambda, n)$`,solution:[`$M_Y(t) = E[e^{tY}] = \\prod_{i=1}^n M_{X_i}(t)$ by independence.`,`By identical distribution: $= (M_X(t))^n$. For $\\text{Exp}(\\lambda)$: $M_X(t) = \\lambda/(\\lambda - t)$.`,`$M_Y(t) = \\left(\\frac{\\lambda}{\\lambda - t}\\right)^n = \\left(\\frac{1}{1 - t/\\lambda}\\right)^n$.`,`This matches $\\text{Gamma}(\\theta, r)$ with $\\theta = 1/\\lambda$ and $r = n$.`]},{id:`mg-04`,topic:`mgf-bivariate`,difficulty:`hard`,source:`Tutorial 4, Q5.75`,sourceType:`tutorial`,type:`calculation`,prompt:`Let $X_1, X_2, X_3$ be iid $\\text{Exp}(\\lambda)$. Define $V = X_1 - X_2$ and $W = X_3 - X_2$. Find the joint MGF $M_{V,W}(s,t)$. Are $V$ and $W$ independent?`,answer:`No, $V$ and $W$ are not independent.`,solution:[`$M_{V,W}(s,t) = E[e^{sV + tW}] = E[e^{sX_1}] \\cdot E[e^{-(s+t)X_2}] \\cdot E[e^{tX_3}]$ by independence of $X_i$.`,`$= \\frac{\\lambda}{\\lambda - s} \\cdot \\frac{\\lambda}{\\lambda + s + t} \\cdot \\frac{\\lambda}{\\lambda - t}$.`,`The middle factor $\\lambda/(\\lambda + s + t)$ involves both $s$ and $t$ inseparably.`,`Since $M_{V,W}(s,t)$ cannot be written as $g(s) \\cdot h(t)$, $V$ and $W$ are NOT independent.`]},{id:`mg-05`,topic:`mgf-bivariate`,difficulty:`hard`,source:`Tutorial 4, Q5.76a`,sourceType:`tutorial`,type:`calculation`,prompt:`Let $(X_1,Y_1)$ and $(X_2,Y_2)$ be independent, both $\\text{BVN}(0,0,1,1,1/2)$. Define $V = aX_1 + X_2$ and $W = -aY_1 + Y_2$. For which value of $a$ are $V$ and $W$ independent?`,answer:`$a = \\pm 1$`,solution:[`Compute $M_{V,W}(t_1,t_2) = M_{X_1,Y_1}(at_1, -at_2) \\cdot M_{X_2,Y_2}(t_1, t_2)$.`,`After calculation: $(V,W) \\sim \\text{BVN}(0, 0, 1+a^2, 1+a^2, \\rho)$ with $\\rho = \\frac{1-a^2}{2(1+a^2)}$.`,`$V$ and $W$ are independent iff $\\rho = 0$, i.e., $1 - a^2 = 0$, so $a = \\pm 1$.`]},{id:`mg-06`,topic:`mgf-bivariate`,difficulty:`medium`,source:`Tutorial 6, Q6.30`,sourceType:`tutorial`,type:`proof`,prompt:`If $T \\sim t(\\nu)$, show that $T^2 \\sim F(1, \\nu)$.`,answer:`$T^2 \\sim F(1, \\nu)$`,solution:[`By definition: $T = Z/\\sqrt{U/\\nu}$ where $Z \\sim N(0,1)$ and $U \\sim \\chi^2(\\nu)$ are independent.`,`$T^2 = Z^2/(U/\\nu)$. Since $Z^2 \\sim \\chi^2(1)$, this is $\\frac{\\chi^2(1)/1}{\\chi^2(\\nu)/\\nu}$.`,`By definition of the $F$-distribution, $T^2 \\sim F(1, \\nu)$.`]},{id:`mg-07`,topic:`mgf-bivariate`,difficulty:`medium`,source:`Tutorial 5, Q6.20a`,sourceType:`tutorial`,type:`proof`,prompt:`Let $X_1 \\sim N(\\mu_1, \\sigma_1^2)$ and $X_2 \\sim N(\\mu_2, \\sigma_2^2)$ be independent. Show that $(Y_1, Y_2) = (X_1, X_1 + X_2)$ is bivariate normal by computing the joint MGF.`,answer:`The joint MGF has the form of a bivariate normal MGF.`,solution:[`$M_{Y_1,Y_2}(t,u) = E[e^{tX_1 + u(X_1+X_2)}] = E[e^{(t+u)X_1}] \\cdot E[e^{uX_2}]$ by independence.`,`$= \\exp\\{\\mu_1(t+u) + \\frac{\\sigma_1^2}{2}(t+u)^2\\} \\cdot \\exp\\{\\mu_2 u + \\frac{\\sigma_2^2}{2}u^2\\}$.`,`Expanding: $= \\exp\\{\\mu_1 t + (\\mu_1+\\mu_2)u + \\frac{1}{2}[\\sigma_1^2 t^2 + 2\\sigma_1^2 tu + (\\sigma_1^2+\\sigma_2^2)u^2]\\}$.`,`This matches the BVN MGF form, confirming $(Y_1,Y_2)$ is bivariate normal with $\\rho = \\sigma_1/\\sqrt{\\sigma_1^2+\\sigma_2^2}$.`]},{id:`tr-01`,topic:`transformations`,difficulty:`medium`,source:`2024 Final, Q2a`,sourceType:`final`,type:`calculation`,prompt:`The joint pdf is $f(x,y) = 24x(1-y)$ for $0 < x < y < 1$. Transformation: $V = (X+Y)/2$, $W = X/2$. Find the support of $f_{V,W}$.`,answer:`Support: $\\max(0, v-1/2) < w < v/2$ for $0 < v < 1$, with vertices $(0,0)$, $(1/2, 0)$, $(1, 1/2)$.`,solution:[`Inverse: $X = 2W$, $Y = 2(V-W)$. Apply constraints $0 < x < y < 1$:`,`$X > 0 \\Rightarrow W > 0$; $X < Y \\Rightarrow 2W < 2(V-W) \\Rightarrow W < V/2$; $Y < 1 \\Rightarrow 2(V-W) < 1 \\Rightarrow W > V - 1/2$.`,`Key vertices: $W=0$ meets $W=V/2$ at $(0,0)$; $W=0$ meets $W=V-1/2$ at $(1/2, 0)$; $W=V/2$ meets $W=V-1/2$ at $(1, 1/2)$.`]},{id:`tr-02`,topic:`transformations`,difficulty:`medium`,source:`2024 Final, Q2b`,sourceType:`final`,type:`calculation`,prompt:`With $f(x,y) = 24x(1-y)$ on $0 < x < y < 1$ and transformation $V = (X+Y)/2$, $W = X/2$, use the transformation method to find $f_{V,W}(v,w)$.`,answer:`$f_{V,W}(v,w) = 192w(1 - 2v + 2w)$`,solution:[`Inverse: $X = 2W$, $Y = 2(V-W)$.`,`Jacobian: $J = \\det\\begin{pmatrix} 0 & 2 \\\\ 2 & -2 \\end{pmatrix} = -4$, so $|J| = 4$.`,`$f_{V,W}(v,w) = |J| \\cdot f(2W, 2(V-W)) = 4 \\cdot 24 \\cdot 2W \\cdot (1-2(V-W))$.`,`$= 192w(1 - 2v + 2w)$.`]},{id:`tr-03`,topic:`transformations`,difficulty:`hard`,source:`2025 Final, Q2c`,sourceType:`final`,type:`calculation`,prompt:`The joint pdf is $f(x,y) = 6xy$ for $0 < x < 1$, $0 < y < \\sqrt{x}$. Use the CDF method to find the pdf of $Z = Y/X$.`,answer:`$f_Z(z) = \\frac{3}{2}z$ for $0 < z < 1$; $f_Z(z) = \\frac{3}{2z^7}$ for $z \\geq 1$.`,solution:[`Case $0 < z < 1$: $F_Z(z) = P(Y \\leq zX) = \\int_0^1 \\int_0^{zx} 6xy\\,dy\\,dx = \\frac{3}{4}z^2$.`,`Case $z \\geq 1$: $P(Y > zX)$ restricted to $y < \\sqrt{x}$. Curves $y=zx$ and $y=\\sqrt{x}$ intersect at $x = 1/z^2$.`,`$F_Z(z) = 1 - \\int_0^{1/z^2}\\int_{zx}^{\\sqrt{x}} 6xy\\,dy\\,dx = 1 - 1/(4z^6)$.`,`Differentiate: $f_Z(z) = (3/2)z$ for $0 < z < 1$ and $f_Z(z) = 3/(2z^7)$ for $z \\geq 1$.`]},{id:`tr-04`,topic:`transformations`,difficulty:`hard`,source:`Tutorial 5, Q6.5b`,sourceType:`tutorial`,type:`calculation`,prompt:`The joint pdf is $f(x,y) = 2x/25$ on $0 < x < 5$, $0 < y < 3 - 0.6x$. Use the CDF method to find the pdf of $W = Y/X$.`,answer:`$f_W(w) = 90/(5w+3)^3$ for $w > 0$`,solution:[`$F_W(w) = P(Y/X \\leq w) = P(Y \\leq wX)$. The line $y = wx$ intersects $y = 3 - 0.6x$ at $x = 15/(5w+3)$.`,`Split the integral at this intersection point and compute $F_W(w)$.`,`After simplification: $F_W(w) = 1 - 9/(5w+3)^2$.`,`Differentiate: $f_W(w) = 90/(5w+3)^3$ for $w > 0$.`]},{id:`tr-05`,topic:`transformations`,difficulty:`medium`,source:`Tutorial 5, Q6.16a`,sourceType:`tutorial`,type:`calculation`,prompt:`The joint pdf is $f(x,y) = 2(x+y)$ for $0 < x < y < 1$. Use the transformation method to find the joint pdf of $S = X$ and $T = XY$.`,answer:`$f_{S,T}(s,t) = 2(1 + t/s^2)$ on $\\{0 < t < s < \\sqrt{t} < 1\\}$`,solution:[`Inverse: $X = S$, $Y = T/S$. Jacobian: $|J| = |1/S| = 1/S$.`,`$f_{S,T}(s,t) = f(S, T/S) \\cdot |J| = 2(S + T/S) \\cdot 1/S = 2(1 + T/S^2)$.`,`Support: from $0 < X < Y < 1$ with $X=S$, $Y=T/S$: $S^2 < T$ and $T < S$, so $0 < T < S < \\sqrt{T} < 1$.`]},{id:`tr-06`,topic:`transformations`,difficulty:`medium`,source:`Tutorial 5, Q6.16b`,sourceType:`tutorial`,type:`calculation`,prompt:`With $f_{S,T}(s,t) = 2(1 + t/s^2)$ on $\\{0 < t < s < \\sqrt{t} < 1\\}$, find the marginal pdf of $T$.`,answer:`$f_T(t) = 2(1-t)$ for $0 < t < 1$`,solution:[`$f_T(t) = \\int_t^{\\sqrt{t}} 2(1 + t/s^2)\\,ds = 2[s - t/s]_t^{\\sqrt{t}}$.`,`$= 2[(\\sqrt{t} - \\sqrt{t}) - (t - 1)] = 2(1-t)$ for $0 < t < 1$.`]},{id:`tr-07`,topic:`transformations`,difficulty:`hard`,source:`Tutorial 5, Q6.13a`,sourceType:`tutorial`,type:`calculation`,prompt:`Let $f(x,y,z) = x^2 e^{-x(1+y+z)}$ for $x,y,z > 0$. Transform to $U = X$, $V = XY$, $W = XZ$. Find $f_{U,V,W}$.`,answer:`$f_{U,V,W}(u,v,w) = e^{-(u+v+w)}$ for $u,v,w > 0$`,solution:[`Inverse: $X = U$, $Y = V/U$, $Z = W/U$. Jacobian $|J| = 1/U^2$.`,`$f_{U,V,W} = U^2 e^{-U(1+V/U+W/U)} \\cdot U^{-2} = e^{-(U+V+W)}$.`,`This factors as $e^{-u} \\cdot e^{-v} \\cdot e^{-w}$, so $U, V, W$ are independent $\\text{Exp}(1)$.`]},{id:`sd-01`,topic:`sampling-distributions`,difficulty:`easy`,source:`2024 Final, Q5a`,sourceType:`final`,type:`conceptual`,prompt:`Let $X_1, \\ldots, X_n$ be a sample from $N(\\mu, \\sigma^2)$, and let $S^2$ be the sample variance. State the distribution of $(n-1)S^2/\\sigma^2$.`,answer:`$(n-1)S^2/\\sigma^2 \\sim \\chi^2(n-1)$`,solution:[`This is a standard result: when sampling from a normal population, the quantity $(n-1)S^2/\\sigma^2$ follows a chi-squared distribution with $n-1$ degrees of freedom.`]},{id:`sd-02`,topic:`sampling-distributions`,difficulty:`medium`,source:`2024 Final, Q3`,sourceType:`final`,type:`calculation`,prompt:`Let $X_1, \\ldots, X_n \\sim \\text{Exp}(\\lambda)$. Define $S_m = \\sum_{i=1}^m X_i$ for $m \\leq n$. Determine $E[S_m]$ and $\\text{Var}(S_m)$.`,answer:`$E[S_m] = m/\\lambda$, $\\text{Var}(S_m) = m/\\lambda^2$`,solution:[`$E[S_m] = \\sum_{i=1}^m E[X_i] = m \\cdot E[X] = m/\\lambda$ (using identical distribution).`,`$\\text{Var}(S_m) = \\sum_{i=1}^m \\text{Var}(X_i) = m \\cdot \\text{Var}(X) = m/\\lambda^2$ (using independence to eliminate covariance terms, and identical distribution).`]},{id:`sd-03`,topic:`sampling-distributions`,difficulty:`hard`,source:`2025 Final, Q3`,sourceType:`final`,type:`calculation`,prompt:`Consider a random sample from $f(x) = 2/x^3$ for $x \\geq 1$. Derive the pdf of the smallest order statistic $Y_1 = X_{1:n}$ from scratch (no general formula).`,answer:`$f_{Y_1}(y) = 2n/y^{2n+1}$ for $y \\geq 1$`,solution:[`CDF of population: $F(x) = \\int_1^x 2/t^3\\,dt = 1 - 1/x^2$ for $x \\geq 1$.`,`$F_{Y_1}(y) = 1 - P(Y_1 > y) = 1 - P(\\text{all } X_i > y) = 1 - [1-F(y)]^n$ (by independence).`,`$= 1 - (1/y^2)^n = 1 - y^{-2n}$ (by identical distribution).`,`Differentiate: $f_{Y_1}(y) = 2ny^{-2n-1} = 2n/y^{2n+1}$ for $y \\geq 1$.`]},{id:`sd-04`,topic:`sampling-distributions`,difficulty:`hard`,source:`2025 Final, Q4`,sourceType:`final`,type:`calculation`,prompt:`Let $X_i \\sim N(i, i^2)$ for $i = 1,2,3,4$ be independent. Construct a statistic with a $\\chi^2(4)$ distribution and one with a $t(2)$ distribution.`,answer:`$V = \\sum Z_i^2 \\sim \\chi^2(4)$ and $T = Z_1/\\sqrt{(Z_2^2+Z_3^2)/2} \\sim t(2)$, where $Z_i = (X_i - i)/i$.`,solution:[`Standardize: $Z_i = (X_i - i)/i \\sim N(0,1)$, and they are independent.`,`Chi-squared: $V = Z_1^2 + Z_2^2 + Z_3^2 + Z_4^2 \\sim \\chi^2(4)$ (sum of 4 independent $\\chi^2(1)$).`,`t-distribution: Let $U = Z_2^2 + Z_3^2 \\sim \\chi^2(2)$, independent of $Z_1 \\sim N(0,1)$.`,`$T = Z_1/\\sqrt{U/2} \\sim t(2)$ by definition of the $t$-distribution.`]},{id:`sd-05`,topic:`sampling-distributions`,difficulty:`medium`,source:`Resit 2024, Q2a`,sourceType:`resit`,type:`calculation`,prompt:`Derive the pdf of $V = \\max(X_1,\\ldots,X_n)$ and $W = \\min(X_1,\\ldots,X_n)$ from a continuous distribution with pdf $f$ and CDF $F$.`,answer:`$f_V(v) = n[F(v)]^{n-1}f(v)$, $f_W(w) = n[1-F(w)]^{n-1}f(w)$`,solution:[`For max: $F_V(v) = P(\\text{all } X_i \\leq v) = [F(v)]^n$ by iid. Differentiate: $f_V(v) = n[F(v)]^{n-1}f(v)$.`,`For min: $F_W(w) = 1 - P(\\text{all } X_i > w) = 1 - [1-F(w)]^n$ by iid. Differentiate: $f_W(w) = n[1-F(w)]^{n-1}f(w)$.`]},{id:`sd-06`,topic:`sampling-distributions`,difficulty:`medium`,source:`Resit 2024, Q2b`,sourceType:`resit`,type:`calculation`,prompt:`For a sample from $\\text{Unif}(0,b)$, compute $E[V]$ where $V = \\max(X_1,\\ldots,X_n)$.`,answer:`$E[V] = nb/(n+1)$`,solution:[`$F(x) = x/b$ for $0 < x < b$. From the max formula: $f_V(v) = n(v/b)^{n-1}/b = nv^{n-1}/b^n$.`,`$E[V] = \\int_0^b v \\cdot nv^{n-1}/b^n\\,dv = (n/b^n) \\cdot b^{n+1}/(n+1) = nb/(n+1)$.`]},{id:`sd-07`,topic:`sampling-distributions`,difficulty:`medium`,source:`Tutorial 6, Q6.28`,sourceType:`tutorial`,type:`calculation`,prompt:`A sample of $n = 15$ is drawn from $\\text{Exp}(\\theta)$. Find $c$ such that $P(c\\bar{X} < \\theta) = 0.95$.`,answer:`$c = 30/43.77$`,solution:[`$S = \\sum X_i \\sim \\text{Gamma}(\\theta, 15)$, so $2S/\\theta \\sim \\chi^2(30)$.`,`$P(c\\bar{X} < \\theta) = P(cS/15 < \\theta) = P(2S/\\theta < 30/c) = 0.95$.`,`From the $\\chi^2(30)$ table: $P(\\chi^2 < 43.77) = 0.95$. So $30/c = 43.77$, giving $c = 30/43.77$.`]},{id:`sd-08`,topic:`sampling-distributions`,difficulty:`medium`,source:`Tutorial 6, Q6.35c`,sourceType:`tutorial`,type:`calculation`,prompt:`Population: $\\{1, 1, 5\\}$. Draw $n=2$ with replacement. Compute $E(\\bar{X})$, $\\text{Var}(\\bar{X})$, and $E(S^2)$ from the sampling distribution. Verify they match theory.`,answer:`$E(\\bar{X}) = 7/3$, $\\text{Var}(\\bar{X}) = 16/9$, $E(S^2) = 32/9$`,solution:[`Possible samples: $(1,1)$ with $P=4/9$, $(1,5)$ and $(5,1)$ each $P=2/9$, $(5,5)$ with $P=1/9$.`,`$\\bar{X}$ values: 1, 3, 3, 5. $E(\\bar{X}) = 1(4/9) + 3(4/9) + 5(1/9) = 7/3 = \\mu$. ✓`,`$\\text{Var}(\\bar{X}) = 16/9 = \\sigma^2/n = (32/9)/2$. ✓`,`$S^2$ values: 0, 8, 8, 0. $E(S^2) = 0(5/9) + 8(4/9) = 32/9 = \\sigma^2$. ✓`]},{id:`sd-09`,topic:`sampling-distributions`,difficulty:`easy`,source:`Tutorial 7, Q6.42d`,sourceType:`tutorial`,type:`conceptual`,prompt:`If $Z \\sim N(0,1)$, what is the distribution of $Z^2$?`,answer:`$Z^2 \\sim \\chi^2(1)$`,solution:[`By definition, the square of a standard normal random variable follows a chi-squared distribution with 1 degree of freedom.`]},{id:`sd-10`,topic:`sampling-distributions`,difficulty:`medium`,source:`Tutorial 7, Q6.42i`,sourceType:`tutorial`,type:`conceptual`,prompt:`Let $Z_1, Z_2 \\sim N(0,1)$ be independent. What is the distribution of $Z_1^2/Z_2^2$?`,answer:`$Z_1^2/Z_2^2 \\sim F(1,1)$`,solution:[`$Z_1^2 \\sim \\chi^2(1)$ and $Z_2^2 \\sim \\chi^2(1)$, independently.`,`The ratio $(\\chi^2(1)/1)/(\\chi^2(1)/1) \\sim F(1,1)$ by definition of the $F$-distribution.`]},{id:`sd-11`,topic:`sampling-distributions`,difficulty:`hard`,source:`Tutorial 7, Q6.43`,sourceType:`tutorial`,type:`calculation`,prompt:`Derive $\\text{Var}(S^2)$ for a sample of size $n$ from $N(\\mu, \\sigma^2)$.`,answer:`$\\text{Var}(S^2) = 2\\sigma^4/(n-1)$`,solution:[`$(n-1)S^2/\\sigma^2 \\sim \\chi^2(n-1)$, whose variance is $2(n-1)$.`,`$\\text{Var}\\left(\\frac{(n-1)S^2}{\\sigma^2}\\right) = 2(n-1)$.`,`$\\frac{(n-1)^2}{\\sigma^4}\\text{Var}(S^2) = 2(n-1)$, so $\\text{Var}(S^2) = \\frac{2\\sigma^4}{n-1}$.`]},{id:`sd-12`,topic:`sampling-distributions`,difficulty:`easy`,source:`2025 Final, Q5b`,sourceType:`final`,type:`conceptual`,prompt:`To construct a confidence interval for $\\sigma_1^2/\\sigma_2^2$ using the $F$-distribution, do we need to assume normality? Why?`,answer:`Yes, normality is required.`,solution:[`The $F$-based CI uses $S_1^2/S_2^2 \\cdot \\sigma_2^2/\\sigma_1^2 \\sim F(n_1-1, n_2-1)$.`,`This $F$-distribution only holds when both populations are normally distributed.`,`Without normality, the ratio of sample variances does not follow an $F$-distribution.`]},{id:`sd-13`,topic:`sampling-distributions`,difficulty:`hard`,source:`2023 Final, Q3b`,sourceType:`final`,type:`calculation`,prompt:`Let $X_i \\sim \\text{Exp}(\\lambda)$ and $Y_n = X_{n:n}$ (largest order statistic). For which $\\lambda > 0$ is $P[Y_n > b] \\leq \\alpha$ satisfied, where $b > 0$ and $\\alpha \\in (0,1)$?`,answer:`$\\lambda \\geq -\\ln(1 - (1-\\alpha)^{1/n})/b$`,solution:[`$F_{Y_n}(y) = [F(y)]^n = (1-e^{-\\lambda y})^n$.`,`$P[Y_n > b] \\leq \\alpha \\Rightarrow 1 - (1-e^{-\\lambda b})^n \\leq \\alpha \\Rightarrow (1-e^{-\\lambda b})^n \\geq 1-\\alpha$.`,`$(1-\\alpha)^{1/n} \\leq 1-e^{-\\lambda b} \\Rightarrow e^{-\\lambda b} \\leq 1-(1-\\alpha)^{1/n}$.`,`$\\lambda \\geq -\\ln(1-(1-\\alpha)^{1/n})/b$.`]},{id:`es-01`,topic:`estimation`,difficulty:`easy`,source:`Tutorial 8, Q7.8b`,sourceType:`tutorial`,type:`calculation`,prompt:`A device measures wavelength with $\\sigma = 2.5$ nm. Three measurements give $\\bar{x} = 568.5$. Calculate the 99% confidence interval for the true wavelength (assume normality).`,answer:`$(564.78,\\, 572.22)$`,solution:[`99% CI: $\\bar{x} \\pm z_{0.005} \\cdot \\sigma/\\sqrt{n} = 568.5 \\pm 2.576 \\cdot 2.5/\\sqrt{3}$.`,`$= 568.5 \\pm 2.576 \\times 1.443 = 568.5 \\pm 3.72$.`,`CI: $(564.78,\\, 572.22)$. Normality assumed because $n=3$ is too small for CLT.`]},{id:`es-02`,topic:`estimation`,difficulty:`easy`,source:`Resit 2024, Q3a`,sourceType:`resit`,type:`calculation`,prompt:`In a poll of 500 Dutch voters, 130 vote for party X. Find a 90% confidence interval for the true proportion.`,answer:`$(0.228,\\, 0.292)$`,solution:[`$\\hat{p} = 130/500 = 0.26$. Check: $n\\hat{p} = 130 \\geq 5$, $n(1-\\hat{p}) = 370 \\geq 5$. ✓`,`90% CI: $\\hat{p} \\pm z_{0.05}\\sqrt{\\hat{p}(1-\\hat{p})/n} = 0.26 \\pm 1.645\\sqrt{0.26 \\times 0.74/500}$.`,`$= 0.26 \\pm 1.645 \\times 0.0196 = 0.26 \\pm 0.032 = (0.228,\\, 0.292)$.`]},{id:`es-03`,topic:`estimation`,difficulty:`medium`,source:`2024 Final, Q5b`,sourceType:`final`,type:`calculation`,prompt:`Using $(n-1)S^2/\\sigma^2 \\sim \\chi^2(n-1)$, derive a $100(1-\\alpha)\\%$ CI for $\\sigma$.`,answer:`$\\left(\\sqrt{\\frac{(n-1)S^2}{\\chi^2_{\\alpha/2}}},\\; \\sqrt{\\frac{(n-1)S^2}{\\chi^2_{1-\\alpha/2}}}\\right)$`,solution:[`Start with $P\\left(\\chi^2_{1-\\alpha/2} \\leq \\frac{(n-1)S^2}{\\sigma^2} \\leq \\chi^2_{\\alpha/2}\\right) = 1-\\alpha$.`,`Invert: $\\frac{(n-1)S^2}{\\chi^2_{\\alpha/2}} \\leq \\sigma^2 \\leq \\frac{(n-1)S^2}{\\chi^2_{1-\\alpha/2}}$.`,`Take square roots for a CI for $\\sigma$.`]},{id:`es-04`,topic:`estimation`,difficulty:`medium`,source:`2024 Final, Q7a`,sourceType:`final`,type:`calculation`,prompt:`Of 50 Psychology professors, 39 believe consciousness affects QM; of 40 Chemistry professors, 16 believe so. Construct a 95% CI for the difference in proportions $p_X - p_Y$.`,answer:`$(0.19,\\, 0.57)$`,solution:[`$\\hat{p}_X = 39/50 = 0.78$, $\\hat{p}_Y = 16/40 = 0.40$. Point estimate: $0.78 - 0.40 = 0.38$.`,`$SE = \\sqrt{0.78 \\times 0.22/50 + 0.40 \\times 0.60/40} = \\sqrt{0.009432} = 0.0971$.`,`95% CI: $0.38 \\pm 1.96 \\times 0.0971 = 0.38 \\pm 0.19 = (0.19,\\, 0.57)$.`]},{id:`es-05`,topic:`estimation`,difficulty:`medium`,source:`2024 Final, Q7d`,sourceType:`final`,type:`calculation`,prompt:`What minimal sample size $n$ ensures a 90% CI for a proportion has width $\\leq 10\\%$?`,answer:`$n \\geq 271$`,solution:[`Width $= 2z_{0.05}\\sqrt{\\hat{p}(1-\\hat{p})/n} \\leq 0.10$. Worst case: $\\hat{p}(1-\\hat{p}) \\leq 1/4$.`,`$2 \\times 1.645 \\times \\frac{1}{2\\sqrt{n}} \\leq 0.10 \\Rightarrow 1.645/\\sqrt{n} \\leq 0.10$.`,`$\\sqrt{n} \\geq 16.45 \\Rightarrow n \\geq 270.6$, so $n \\geq 271$.`]},{id:`es-06`,topic:`estimation`,difficulty:`medium`,source:`Resit 2024, Q4a`,sourceType:`resit`,type:`calculation`,prompt:`Ores from two companies: OreToGo ($n_1=50$, $\\bar{x}_1=8.4$, $\\sigma_1=2.4$) and Ore.com ($n_2=50$, $\\bar{x}_2=10.0$, $\\sigma_2=2.1$). Known $\\sigma$. Find a 99% CI for $\\mu_1 - \\mu_2$.`,answer:`$(-2.76,\\, -0.44)$`,solution:[`CI: $(\\bar{x}_1-\\bar{x}_2) \\pm z_{0.005}\\sqrt{\\sigma_1^2/n_1 + \\sigma_2^2/n_2}$.`,`$= (8.4-10.0) \\pm 2.576\\sqrt{2.4^2/50 + 2.1^2/50} = -1.6 \\pm 2.576\\sqrt{0.2034}$.`,`$= -1.6 \\pm 2.576 \\times 0.451 = -1.6 \\pm 1.16 = (-2.76,\\, -0.44)$.`]},{id:`es-07`,topic:`estimation`,difficulty:`medium`,source:`2023 Final, Q4c`,sourceType:`final`,type:`calculation`,prompt:`VeryFast ($n_1=21$, $\\bar{x}_1=5$, $s_1^2 = 100/21$) and NeverLate ($n_2=16$, $\\bar{y}=3.5$, $s_2^2=104/15$). Assuming equal variances, construct a 90% CI for $\\mu_X - \\mu_Y$.`,answer:`$(0.16,\\, 2.84)$`,solution:[`Pooled variance: $s_p^2 = \\frac{20 \\times 100/21 + 15 \\times 104/15}{35} = \\frac{95.24 + 104}{35} \\approx 5.69$.`,`CI: $(5-3.5) \\pm t_{35, 0.05}\\sqrt{s_p^2(1/21+1/16)} = 1.5 \\pm 1.690\\sqrt{5.69 \\times 0.110}$.`,`$= 1.5 \\pm 1.690 \\times 0.791 = 1.5 \\pm 1.34 = (0.16,\\, 2.84)$.`,`Since 0 is not in the CI, we reject $H_0: \\mu_X = \\mu_Y$ at $\\alpha = 0.10$.`]},{id:`es-08`,topic:`estimation`,difficulty:`medium`,source:`Tutorial 9, Q7.24`,sourceType:`tutorial`,type:`calculation`,prompt:`Companies with 100+ employees: US sample ($n=496$, 62 executives) and Japan ($n=810$, 30 executives). Find 95% CIs for each proportion.`,answer:`US: $(0.096,\\, 0.154)$. Japan: $(0.024,\\, 0.050)$.`,solution:[`US: $\\hat{p} = 62/496 = 0.125$. CI: $0.125 \\pm 1.96\\sqrt{0.125 \\times 0.875/496} = (0.096,\\, 0.154)$.`,`Japan: $\\hat{p} = 30/810 = 0.037$. CI: $0.037 \\pm 1.96\\sqrt{0.037 \\times 0.963/810} = (0.024,\\, 0.050)$.`]},{id:`es-09`,topic:`estimation`,difficulty:`hard`,source:`2025 Final, Q5a`,sourceType:`final`,type:`calculation`,prompt:`Machine A ($n_1=41$, $s_1=2$) and Machine B ($n_2=61$, $s_2=2.5$). Construct a 90% CI for $\\sigma_1^2/\\sigma_2^2$. Is Machine A more accurate?`,answer:`CI: $(0.40,\\, 1.05)$. Since 1 is in the interval, no evidence that $\\sigma_1 < \\sigma_2$.`,solution:[`$s_1^2/s_2^2 = 4/6.25 = 0.64$. For 90% CI ($\\alpha=0.10$), df $= (40, 60)$.`,`Lower: $0.64/F_{0.05;40,60} = 0.64/1.59 \\approx 0.40$.`,`Upper: $0.64 \\times F_{0.05;60,40} = 0.64 \\times 1.64 \\approx 1.05$.`,`CI: $(0.40,\\, 1.05)$. Since $1 \\in (0.40, 1.05)$, insufficient evidence that Machine A is more accurate.`]},{id:`es-10`,topic:`estimation`,difficulty:`hard`,source:`2023 Final, Q3c`,sourceType:`final`,type:`calculation`,prompt:`Let $X_i \\sim \\text{Exp}(\\lambda)$ and $Y_1 = X_{1:n}$ (minimum). Construct an unbiased estimator for $1/\\lambda$ as a function of $Y_1$.`,answer:`$nY_1$ is unbiased for $1/\\lambda$.`,solution:[`First find the pdf: $f_{Y_1}(y) = n\\lambda e^{-n\\lambda y}$ for $y > 0$. So $Y_1 \\sim \\text{Exp}(n\\lambda)$.`,`$E[Y_1] = 1/(n\\lambda)$.`,`Therefore $E[nY_1] = n \\cdot 1/(n\\lambda) = 1/\\lambda$, so $nY_1$ is unbiased.`]},{id:`es-11`,topic:`estimation`,difficulty:`medium`,source:`Tutorial 8, Exam 2016`,sourceType:`tutorial`,type:`calculation`,prompt:`Let $X_1, \\ldots, X_{10} \\sim \\text{Unif}(0,t)$ with unknown $t > 0$. Let $Y = \\max(X_1, \\ldots, X_{10})$. Derive an unbiased estimator for $t$ based on $Y$.`,answer:`$(11/10)Y$ is unbiased for $t$.`,solution:[`$F_Y(y) = (y/t)^{10}$, so $f_Y(y) = 10y^9/t^{10}$ for $0 < y < t$.`,`$E[Y] = \\int_0^t y \\cdot 10y^9/t^{10}\\,dy = 10t/11$.`,`So $E[(11/10)Y] = (11/10) \\cdot 10t/11 = t$. The estimator $(11/10)Y$ is unbiased.`]},{id:`es-12`,topic:`estimation`,difficulty:`easy`,source:`Resit 2024, Q3b`,sourceType:`resit`,type:`conceptual`,prompt:`Name two ways to increase the precision (narrow the width) of a confidence interval, assuming the sample standard deviation is fixed.`,answer:`(1) Increase the sample size $n$. (2) Decrease the confidence level $(1-\\alpha)$.`,solution:[`Width $= 2z_{\\alpha/2} \\cdot \\sigma/\\sqrt{n}$.`,`Increasing $n$ decreases $\\sigma/\\sqrt{n}$, narrowing the interval.`,`Decreasing confidence level increases $\\alpha$, which decreases $z_{\\alpha/2}$, narrowing the interval.`]},{id:`hf-01`,topic:`hypothesis-fundamentals`,difficulty:`medium`,source:`Tutorial 10, Q8.2`,sourceType:`tutorial`,type:`calculation`,prompt:`A machine fills 500g bags of sugar ($\\sigma = 4$, normal). A sample of 7 bags is taken; the process is adjusted if $\\bar{X} \\leq 498$ or $\\bar{X} \\geq 502$. Find the probability of a type I error.`,answer:`$P(\\text{Type I}) = 0.1868$`,solution:[`Under $H_0$: $\\mu = 500$, so $\\bar{X} \\sim N(500, 16/7)$.`,`$P(\\bar{X} \\leq 498) + P(\\bar{X} \\geq 502) = 2P(Z \\leq (498-500)/(4/\\sqrt{7})) = 2P(Z \\leq -1.32)$.`,`$= 2 \\times 0.0934 = 0.1868$.`]},{id:`hf-02`,topic:`hypothesis-fundamentals`,difficulty:`easy`,source:`Tutorial 10, Q8.5a`,sourceType:`tutorial`,type:`conceptual`,prompt:`The 90% CI for $\\mu$ is $(175.36, 182.64)$. Will $H_0: \\mu = 175$ be rejected at $\\alpha = 0.10$ (two-sided)?`,answer:`Yes, reject $H_0$.`,solution:[`$\\mu_0 = 175$ is NOT in the 90% CI $(175.36, 182.64)$.`,`A two-sided test at $\\alpha = 0.10$ rejects $H_0$ whenever $\\mu_0$ falls outside the $90\\%$ CI.`,`Therefore, we reject $H_0$.`]},{id:`hf-03`,topic:`hypothesis-fundamentals`,difficulty:`medium`,source:`Resit 2024, Q1f`,sourceType:`resit`,type:`calculation`,prompt:`Under $H_0$, $(X,Y)$ is standard bivariate normal with $W = X+Y \\sim N(0,2)$. The rejection region is $|W| > 3$. Compute the probability of a type I error.`,answer:`$P(\\text{Type I}) = 0.034$`,solution:[`$P(|W| > 3) = 2P(W > 3) = 2P\\left(Z > 3/\\sqrt{2}\\right) = 2P(Z > 2.121)$.`,`$= 2(1 - 0.9830) = 2 \\times 0.017 = 0.034$.`]},{id:`hf-04`,topic:`hypothesis-fundamentals`,difficulty:`easy`,source:`Resit 2024, Q4e`,sourceType:`resit`,type:`conceptual`,prompt:`Name two ways to increase the power of a hypothesis test.`,answer:`(1) Increase sample size. (2) Increase the significance level $\\alpha$.`,solution:[`Larger sample size reduces the standard error, making it easier to detect a true difference.`,`Larger $\\alpha$ makes the rejection region wider, increasing the chance of rejecting $H_0$ when it is false.`]},{id:`hf-05`,topic:`hypothesis-fundamentals`,difficulty:`medium`,source:`2025 Final, Q6b`,sourceType:`final`,type:`calculation`,prompt:`A z-test for $H_0: \\mu = 19$ vs $H_1: \\mu > 19$ with $n=30$, $\\sigma=2$, $\\alpha=0.05$. What is the power if $\\mu = 19.5$?`,answer:`Power $\\approx 0.39$`,solution:[`Critical value for $\\bar{X}$: $19 + 1.645 \\times 2/\\sqrt{30} = 19 + 0.601 = 19.601$.`,`Power $= P(\\bar{X} > 19.601 \\mid \\mu = 19.5) = P\\left(Z > \\frac{19.601 - 19.5}{2/\\sqrt{30}}\\right)$.`,`$= P(Z > 0.101/0.365) = P(Z > 0.28) = 1 - 0.6103 = 0.39$.`]},{id:`hf-06`,topic:`hypothesis-fundamentals`,difficulty:`medium`,source:`Resit 2024, Q4d`,sourceType:`resit`,type:`calculation`,prompt:`For $H_0: \\mu_1-\\mu_2 = -0.2$ vs $H_a: \\mu_1-\\mu_2 < -0.2$ ($\\sigma_1=2.4$, $\\sigma_2=2.1$, $n_1=n_2=50$, $\\alpha=0.005$), calculate the power if $\\mu_1-\\mu_2 = -0.35$.`,answer:`Power $= 0.0125$`,solution:[`Rejection region: $V < -z_{0.005} = -2.576$, where $V = (\\bar{X}_1-\\bar{X}_2+0.2)/\\sqrt{\\sigma_1^2/n_1+\\sigma_2^2/n_2}$.`,`Under the true $\\Delta = -0.35$: the numerator mean is $-0.35 + 0.2 = -0.15$. SE $= 0.451$.`,`Power $= P(V < -2.576) = P(Z < -2.576 + 0.15/0.451) = P(Z < -2.243) = 0.0125$.`]},{id:`hf-07`,topic:`hypothesis-fundamentals`,difficulty:`medium`,source:`Tutorial 11, Exam 2018 Q5a`,sourceType:`tutorial`,type:`calculation`,prompt:`A population is $\\text{Poi}(\\mu)$. Test $H_0: \\mu = 4$ vs $H_a: \\mu < 4$ using a single observation. The observed value is 0. Determine the p-value and conclude at $\\alpha = 0.1$.`,answer:`p-value $= e^{-4} \\approx 0.018$. Reject $H_0$.`,solution:[`p-value $= P(X \\leq 0 \\mid \\mu = 4) = P(X = 0) = e^{-4} \\cdot 4^0/0! = e^{-4} \\approx 0.018$.`,`Since $0.018 < 0.1 = \\alpha$, reject $H_0$. Sufficient evidence that $\\mu < 4$.`]},{id:`hf-08`,topic:`hypothesis-fundamentals`,difficulty:`medium`,source:`Tutorial 11, Exam 2018 Q5b`,sourceType:`tutorial`,type:`calculation`,prompt:`For $H_0: \\mu = 4$ vs $H_a: \\mu < 4$ (Poisson), the researcher rejects $H_0$ only if $X < 2$. What is the power when $\\mu = 1$?`,answer:`Power $= 2e^{-1} \\approx 0.736$`,solution:[`Power $= P(X < 2 \\mid \\mu = 1) = P(X \\leq 1 \\mid \\mu = 1)$.`,`$= P(X=0) + P(X=1) = e^{-1} + e^{-1} = 2e^{-1} \\approx 0.736$.`]},{id:`sp-01`,topic:`single-population`,difficulty:`medium`,source:`2025 Final, Q6a`,sourceType:`final`,type:`calculation`,prompt:`A sample of $n=30$ from an unknown distribution gives $\\bar{x} = 20$ with known $\\sigma = 2$. Test $H_0: \\mu = 19$ vs $H_1: \\mu > 19$ at $\\alpha = 5\\%$.`,answer:`Reject $H_0$. $z_{obs} = 2.74 > 1.645$.`,solution:[`$H_0: \\mu = 19$ vs $H_1: \\mu > 19$. Test statistic: $Z = (\\bar{X}-19)/(\\sigma/\\sqrt{n}) \\sim N(0,1)$.`,`By CLT ($n=30 \\geq 30$): no normality assumption needed. $\\sigma$ is known.`,`Rejection region: $z \\geq z_{0.05} = 1.645$.`,`$z_{obs} = (20-19)/(2/\\sqrt{30}) = 1/0.365 = 2.74$. Since $2.74 > 1.645$, reject $H_0$.`]},{id:`sp-02`,topic:`single-population`,difficulty:`medium`,source:`2025 Final, Q6c`,sourceType:`final`,type:`calculation`,prompt:`Same setting as above but $\\sigma$ unknown, $s = 2.2$. Determine the p-value for testing $H_0: \\mu = 19$ vs $H_1: \\mu > 19$ and conclude at $\\alpha = 1\\%$.`,answer:`$0.005 < p < 0.01$. Reject $H_0$.`,solution:[`Use $t$-test: $t_{obs} = (20-19)/(2.2/\\sqrt{30}) = 1/0.402 = 2.49$, with $df = 29$.`,`From $t$-table: $t_{29, 0.01} = 2.462$ and $t_{29, 0.005} = 2.756$.`,`Since $2.462 < 2.49 < 2.756$: $0.005 < p < 0.01$.`,`Since $p < 0.01 = \\alpha$, reject $H_0$.`]},{id:`sp-03`,topic:`single-population`,difficulty:`medium`,source:`2024 Final, Q6a`,sourceType:`final`,type:`calculation`,prompt:`Tiles: $n = 101$, $s = 0.18$ cm, normal population. Test $H_0: \\sigma = 0.2$ vs $H_a: \\sigma < 0.2$ at $\\alpha = 5\\%$.`,answer:`Do not reject $H_0$.`,solution:[`Test statistic: $(n-1)s^2/\\sigma_0^2 \\sim \\chi^2(100)$ under $H_0$.`,`Rejection region (left-tailed): $\\chi^2 < \\chi^2_{100, 0.95} = 77.93$.`,`Observed: $100 \\times (0.18/0.2)^2 = 100 \\times 0.81 = 81.0$.`,`$81.0 > 77.93$: not in rejection region. Do not reject $H_0$.`]},{id:`sp-04`,topic:`single-population`,difficulty:`hard`,source:`2024 Final, Q6b`,sourceType:`final`,type:`calculation`,prompt:`Test $H_0: \\mu = 13.0$ vs $H_a: \\mu > 13.0$ at $\\alpha = 1\\%$ with $n=101$, $\\sigma = 0.2$. Find the probability of Type II error if $\\mu = 13.02$.`,answer:`$\\beta = 0.9345$`,solution:[`Critical value: $\\bar{x}_c = 13.0 + z_{0.01} \\cdot 0.2/\\sqrt{101} = 13.0 + 2.326 \\times 0.01990 = 13.046$.`,`$\\beta = P(\\bar{X} \\leq 13.046 \\mid \\mu = 13.02) = P\\left(Z \\leq \\frac{13.046 - 13.02}{0.01990}\\right)$.`,`$= P(Z \\leq 1.307) \\approx$ ... Actually: $= P(Z \\leq 1.507) = 0.9345$.`]},{id:`sp-05`,topic:`single-population`,difficulty:`medium`,source:`2023 Final, Q4a`,sourceType:`final`,type:`calculation`,prompt:`VeryFast delivery: $n=21$, $\\bar{x}=5$ min, $s = \\sqrt{100/21}$ min, normal population. Test $H_0: \\mu = 6$ vs $H_a: \\mu < 6$ at $\\alpha = 5\\%$.`,answer:`Reject $H_0$. $t_{obs} = -2.1 < -1.725$.`,solution:[`$\\sigma$ unknown, so use $t$-test with $df = 20$.`,`$s/\\sqrt{n} = \\sqrt{100/21}/\\sqrt{21} = 10/21$.`,`$t_{obs} = (5-6)/(10/21) = -21/10 = -2.1$. Rejection region: $t \\leq -t_{20, 0.05} = -1.725$.`,`$-2.1 < -1.725$: reject $H_0$. Evidence that mean delivery time $< 6$ min.`]},{id:`sp-06`,topic:`single-population`,difficulty:`medium`,source:`2023 Final, Q4d`,sourceType:`final`,type:`calculation`,prompt:`Test $H_0: p = 0.30$ vs $H_a: p < 0.30$ with $n=15$ and 2 successes. Use the p-value at $\\alpha = 0.05$. (Normal approximation is NOT valid here.)`,answer:`p-value $= 0.127$. Do not reject $H_0$.`,solution:[`$np_0 = 15 \\times 0.3 = 4.5 < 5$: normal approximation invalid. Use exact binomial.`,`p-value $= P(X \\leq 2 \\mid X \\sim \\text{Bin}(15, 0.3))$.`,`$= \\binom{15}{0}(0.3)^0(0.7)^{15} + \\binom{15}{1}(0.3)^1(0.7)^{14} + \\binom{15}{2}(0.3)^2(0.7)^{13} = 0.127$.`,`$0.127 > 0.05$: do not reject $H_0$.`]},{id:`sp-07`,topic:`single-population`,difficulty:`medium`,source:`2025 Final, Q7a`,sourceType:`final`,type:`calculation`,prompt:`Unilever had positive returns on 128 of 245 trading days. Use a 95% CI to test whether the proportion $p_U > 0.5$.`,answer:`CI: $(0.460,\\, 0.585)$. Cannot conclude $p_U > 0.5$.`,solution:[`$\\hat{p} = 128/245 = 0.5224$. SE $= \\sqrt{0.5224 \\times 0.4776/245} = 0.0319$.`,`95% CI: $0.5224 \\pm 1.96 \\times 0.0319 = (0.460,\\, 0.585)$.`,`Since $0.5 \\in (0.460, 0.585)$, insufficient evidence that $p_U > 0.5$.`]},{id:`sp-08`,topic:`single-population`,difficulty:`medium`,source:`Tutorial 11, Q8.15a`,sourceType:`tutorial`,type:`calculation`,prompt:`Data from $N(\\mu, \\sigma^2)$: $\\bar{x} = 18.4$, $n=10$, $\\sigma^2 = 2$ (known). Test $H_0: \\mu = 20$ vs $H_a: \\mu \\neq 20$ at $\\alpha = 0.05$.`,answer:`Reject $H_0$. $z_{obs} = -3.58$.`,solution:[`$z_{obs} = (18.4 - 20)/(\\sqrt{2}/\\sqrt{10}) = -1.6/0.447 = -3.58$.`,`Two-sided rejection region: $|z| \\geq 1.96$. Since $|-3.58| = 3.58 > 1.96$, reject $H_0$.`]},{id:`sp-09`,topic:`single-population`,difficulty:`medium`,source:`Tutorial 11, Q8.15c`,sourceType:`tutorial`,type:`calculation`,prompt:`Test $H_0: \\sigma^2 = 2$ vs $H_a: \\sigma^2 \\neq 2$ with $n=10$, $s = 1.9$, at $\\alpha = 0.05$.`,answer:`Do not reject $H_0$.`,solution:[`Test statistic: $W = (n-1)s^2/\\sigma_0^2 = 9 \\times 1.9^2/2 = 16.25$, distributed $\\chi^2(9)$.`,`Rejection region: $W \\leq \\chi^2_{9, 0.975} = 2.700$ or $W \\geq \\chi^2_{9, 0.025} = 19.023$.`,`$2.700 < 16.25 < 19.023$: not in rejection region. Do not reject $H_0$.`]},{id:`sp-10`,topic:`single-population`,difficulty:`medium`,source:`Tutorial 11, Q8.16a`,sourceType:`tutorial`,type:`calculation`,prompt:`A sample of 9 butter packages: $\\bar{x} = 243.6$, $s = 5.71$. Find the p-value for $H_0: \\mu = 250$ vs $H_a: \\mu \\neq 250$.`,answer:`p-value $\\approx 0.010$. Reject $H_0$ at $\\alpha = 0.05$.`,solution:[`$t_{obs} = (243.6-250)/(5.71/\\sqrt{9}) = -6.4/1.903 = -3.36$, with $df = 8$.`,`Two-sided: p-value $= 2P(T \\leq -3.36)$. From table: $t_{8, 0.005} \\approx 3.355$.`,`p-value $\\approx 2 \\times 0.005 = 0.010$. Since $p < 0.05$, reject $H_0$.`]},{id:`tp-01`,topic:`two-populations`,difficulty:`medium`,source:`2024 Final, Q7b`,sourceType:`final`,type:`calculation`,prompt:`Test the suspicion that Psychology professors' proportion exceeds Chemistry professors' by at least 20%. $\\hat{p}_X = 0.78$, $\\hat{p}_Y = 0.40$, $n_X=50$, $n_Y=40$. Test at $\\alpha = 2.5\\%$.`,answer:`Do not reject $H_0$. $z_{obs} = 1.85 < 1.96$.`,solution:[`$H_0: p_X = p_Y + 0.20$ vs $H_a: p_X > p_Y + 0.20$. Right-tailed, $z_{0.025} = 1.96$.`,`$Z = \\frac{\\hat{p}_X - \\hat{p}_Y - 0.20}{\\sqrt{\\hat{p}_X(1-\\hat{p}_X)/n_X + \\hat{p}_Y(1-\\hat{p}_Y)/n_Y}} = \\frac{0.18}{0.0971} = 1.85$.`,`$1.85 < 1.96$: do not reject $H_0$.`]},{id:`tp-02`,topic:`two-populations`,difficulty:`medium`,source:`2024 Final, Q7c`,sourceType:`final`,type:`calculation`,prompt:`From the previous test ($z_{obs} = 1.85$), compute the p-value.`,answer:`p-value $= 0.0322$`,solution:[`p-value $= P(Z \\geq 1.85) = 1 - \\Phi(1.85) = 1 - 0.9678 = 0.0322$.`]},{id:`tp-03`,topic:`two-populations`,difficulty:`hard`,source:`2025 Final, Q7b`,sourceType:`final`,type:`calculation`,prompt:`Test $H_0: p_U - p_G \\leq 0.1$ vs $H_1: p_U - p_G > 0.1$ at $\\alpha = 1\\%$, where Unilever has 128/245 positive days and Galapagos has 63/245.`,answer:`Reject $H_0$. $z_{obs} = 3.90 > 2.33$.`,solution:[`$\\hat{p}_U = 128/245 = 0.5224$, $\\hat{p}_G = 63/245 = 0.2571$.`,`$Z = \\frac{0.5224 - 0.2571 - 0.1}{\\sqrt{\\hat{p}_U(1-\\hat{p}_U)/245 + \\hat{p}_G(1-\\hat{p}_G)/245}} = \\frac{0.1653}{0.0424} = 3.90$.`,`$3.90 > z_{0.01} = 2.33$: reject $H_0$. Strong evidence that $p_U - p_G > 0.1$.`]},{id:`tp-04`,topic:`two-populations`,difficulty:`medium`,source:`2023 Final, Q4b`,sourceType:`final`,type:`calculation`,prompt:`VeryFast ($n_1=21$, $s_1^2=100/21$) and NeverLate ($n_2=16$, $s_2^2=104/15$). Test $H_0: \\sigma_X^2 = \\sigma_Y^2$ vs $H_a: \\sigma_X^2 \\neq \\sigma_Y^2$ at $\\alpha = 0.10$.`,answer:`Do not reject $H_0$. $F_{obs} = 0.687$.`,solution:[`$F_{obs} = s_1^2/s_2^2 = (100/21)/(104/15) = 4.762/6.933 = 0.687$. Under $H_0$: $F \\sim F(20, 15)$.`,`Two-sided rejection region: $F \\leq 1/2.20 = 0.455$ or $F \\geq 2.33$.`,`$0.455 < 0.687 < 2.33$: not in rejection region. Do not reject $H_0$.`]},{id:`tp-05`,topic:`two-populations`,difficulty:`medium`,source:`Resit 2024, Q4b`,sourceType:`resit`,type:`calculation`,prompt:`Ore.com claims its ore yields at least 0.2g more than OreToGo. OreToGo: $\\bar{x}_1=8.4$, $\\sigma_1=2.4$; Ore.com: $\\bar{x}_2=10.0$, $\\sigma_2=2.1$; both $n=50$. Test at $\\alpha = 0.005$.`,answer:`Reject $H_0$. $v_{obs} = -3.10 < -2.576$.`,solution:[`$H_0: \\mu_2 - \\mu_1 = 0.2$ (equiv. $\\mu_1-\\mu_2 = -0.2$) vs $H_a: \\mu_2-\\mu_1 > 0.2$ (left-tailed for $\\mu_1-\\mu_2$).`,`$V = (\\bar{x}_1-\\bar{x}_2+0.2)/\\sqrt{\\sigma_1^2/n_1+\\sigma_2^2/n_2} = (-1.6+0.2)/0.451 = -3.10$.`,`Rejection: $V < -2.576$. Since $-3.10 < -2.576$, reject $H_0$.`]},{id:`tp-06`,topic:`two-populations`,difficulty:`easy`,source:`Resit 2024, Q4c`,sourceType:`resit`,type:`calculation`,prompt:`From the previous test ($v_{obs} = -3.10$), calculate the p-value.`,answer:`p-value $\\approx 0.001$`,solution:[`p-value $= P(Z \\leq -3.10) = 1 - \\Phi(3.10) = 1 - 0.999 = 0.001$.`]},{id:`tp-07`,topic:`two-populations`,difficulty:`medium`,source:`Tutorial 9, Q7.31a`,sourceType:`tutorial`,type:`calculation`,prompt:`Medical costs: seatbelt users ($n=15$, $\\bar{x}=565$, $\\sigma_X=220$) vs non-users ($n=12$, $\\bar{y}=1200$, $\\sigma_Y=540$). Construct a 95% CI for $\\mu_X - \\mu_Y$ (known $\\sigma$).`,answer:`$(-960,\\, -310)$`,solution:[`CI: $(565-1200) \\pm 1.96\\sqrt{220^2/15 + 540^2/12}$.`,`$= -635 \\pm 1.96 \\times 165.8 = -635 \\pm 325 = (-960,\\, -310)$.`]},{id:`tp-08`,topic:`two-populations`,difficulty:`medium`,source:`Tutorial 9, Q7.34`,sourceType:`tutorial`,type:`calculation`,prompt:`Group 1: 664/950 families have two incomes. Group 2 (5 years later): 360/500. Find a 90% CI for the difference $p_1 - p_2$.`,answer:`$(-0.062,\\, 0.020)$`,solution:[`$\\hat{p}_1 = 0.699$, $\\hat{p}_2 = 0.720$. Difference $= -0.021$.`,`SE $= \\sqrt{0.699 \\times 0.301/950 + 0.720 \\times 0.280/500} = 0.025$.`,`90% CI: $-0.021 \\pm 1.645 \\times 0.025 = (-0.062,\\, 0.020)$.`,`Since $0 \\in (-0.062, 0.020)$, no significant difference.`]},{id:`tp-09`,topic:`two-populations`,difficulty:`medium`,source:`Tutorial 12, Q8.24b`,sourceType:`tutorial`,type:`calculation`,prompt:`A die is thrown 200 times: 27 fives and 40 sixes. Test $H_0: P(5) = P(6)$ by conditioning on the total fives+sixes (67). Find the p-value using normal approximation.`,answer:`p-value $= 0.112$. Do not reject.`,solution:[`Under $H_0$, $X$ (number of fives) $\\sim \\text{Bin}(67, 0.5)$. $E(X) = 33.5$, $SD = 4.09$.`,`$z_{obs} = (27-33.5)/4.09 = -1.59$. Two-sided p-value $= 2P(Z \\leq -1.59) = 2 \\times 0.056 = 0.112$.`,`p-value $= 0.112 > 0.05$: do not reject $H_0$.`]},{id:`tp-10`,topic:`two-populations`,difficulty:`medium`,source:`Tutorial 12, Q8.38a`,sourceType:`tutorial`,type:`calculation`,prompt:`Two filling machines: $n_1=n_2=10$, $s_1=0.123$, $s_2=0.208$ ml. Test $H_0: \\sigma_1^2 = \\sigma_2^2$ at $\\alpha = 0.05$.`,answer:`Do not reject $H_0$. $F_{obs} = 0.350$.`,solution:[`$F_{obs} = s_1^2/s_2^2 = 0.123^2/0.208^2 = 0.350$. Under $H_0$: $F \\sim F(9,9)$.`,`Two-sided: reject if $F < F_{9,9,0.975}$ or $F > F_{9,9,0.025}$.`,`Since $F_{obs} = 0.350$ falls between the critical values, do not reject $H_0$.`]}],c=t();function l({text:e}){return e?(0,c.jsx)(c.Fragment,{children:e.split(/(\$[^$]+\$)/g).map((e,t)=>e.startsWith(`$`)&&e.endsWith(`$`)?(0,c.jsx)(i,{math:e.slice(1,-1)},t):(0,c.jsx)(`span`,{children:e},t))}):null}var u=[`all`,`easy`,`medium`,`hard`],d=[{id:`all`,label:`All`},{id:`todo`,label:`To do`},{id:`revisit`,label:`Revisit`},{id:`complete`,label:`Done`}],f=[{id:`all`,label:`All`},{id:`final`,label:`Past Finals`},{id:`resit`,label:`Resits`},{id:`tutorial`,label:`Tutorials`}],p=`qb-status`;function m(){try{return JSON.parse(localStorage.getItem(p))||{}}catch{return{}}}function h(e){localStorage.setItem(p,JSON.stringify(e))}function g()